--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,34 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  let i = 0
+  while (i < argv.length) {
+    const arg = argv[i]
+    if (arg.startsWith('--')) {
+      const hasEquals = arg.includes('=')
+      let increment = 1
+      if (!hasEquals && i + 1 < argv.length) {
+        if (!argv[i + 1].startsWith('--')) {
+          const key = arg.slice(2)
+          const value = argv[i + 1]
+          result[key] = value
+          increment = 2
+        } else {
+          const key = arg.slice(2)
+          result[key] = true
+        }
+      } else if (hasEquals) {
+        const key = arg.slice(2, arg.indexOf('='))
+        const value = arg.slice(arg.indexOf('=') + 1)
+        result[key] = value
+      } else {
+        const key = arg.slice(2)
+        result[key] = true
+      }
+      i += increment
+    } else {
+      result._.push(arg)
+      i++
+    }
   }
   return result
 }

